"""Auto-generated by create(). Description: Test function for framework verification."""

__test__ = False

from openprogram.agentic_programming.function import agentic_function
from openprogram.agentic_programming.runtime import Runtime

import json
import re


_MISSING_RUNTIME = "__missing_runtime__"


def _fallback_review(code: str) -> dict:
    issues: list[str] = []
    cleaned = (code or "").strip()

    if not cleaned:
        return {
            "summary": "未收到可分析代码。",
            "issues": ["输入为空。"],
            "recommendation": "请提供完整的函数代码。",
        }

    if "@agentic_function" not in cleaned:
        issues.append("未检测到 @agentic_function 装饰器。")

    func_match = re.search(
        r"(?ms)^\s*(?:@[^\n]+\n\s*)*def\s+(?P<name>\w+)\s*\((?P<args>[^)]*)\)\s*(?:->\s*(?P<ret>[^:]+)\s*)?:",
        cleaned,
    )
    if not func_match:
        issues.append("未检测到函数定义。")
    else:
        args = (func_match.group("args") or "").strip()
        ret = (func_match.group("ret") or "").strip()
        if not args:
            issues.append("函数参数为空。")
        else:
            arg_parts = [part.strip() for part in args.split(",") if part.strip()]
            missing_type = [
                part
                for part in arg_parts
                if not part.startswith("*")
                and part not in {"self", "cls"}
                and ":" not in part
            ]
            if missing_type:
                issues.append("部分参数缺少类型注解。")
        if ret == "":
            issues.append("缺少返回类型注解。")

    if not re.search(
        r'(?ms)^\s*(?:@[^\n]+\n\s*)*def\s+\w+\s*\([^)]*\)\s*(?:->\s*[^:]+)?\s*:\s*\n\s*(?:"""|\'\'\')',
        cleaned,
    ):
        issues.append("缺少 docstring。")

    if "runtime.exec(" in cleaned:
        issues.append("函数依赖 runtime.exec，结果会受到外部模型影响。")

    if re.search(r'(?m)^\s*return\s+f?["\']\s*Echo:\s*\{?\s*\w+\s*\}?["\']\s*$', cleaned):
        issues.append("当前逻辑是回显输入，未提供真正的函数分析。")

    if not re.search(r"(?m)^\s*return\b", cleaned):
        issues.append("未检测到 return 语句。")

    if not issues:
        summary = "这是一个用于分析 Python 函数源码的工具，结构完整，可继续作为框架测试样例。"
        recommendation = "如果目标是业务函数，可以进一步明确输入输出约束；如果目标是测试样例，这个版本已经可用。"
    else:
        summary = f"这是一个用于分析 Python 函数源码的工具，当前发现 {len(issues)} 个问题。"
        recommendation = "建议优先补齐注解和 docstring，并尽量减少对 runtime.exec 的隐式依赖。"

    return {
        "summary": summary,
        "issues": issues,
        "recommendation": recommendation,
    }


@agentic_function(input={
    "message": {"description": "Function code to analyze", "multiline": True},
    "runtime": {"hidden": True},
})
def test(message: str, runtime: Runtime = _MISSING_RUNTIME) -> str:
    """Analyze the provided function and return a concise Chinese report.

    Return ONLY JSON text with three keys:
    - summary: one-line summary
    - issues: list of actionable issues
    - recommendation: concrete next step

    The runtime argument is accepted for compatibility but is not used.
    Do not return additional commentary outside the JSON object.

    Args:
        message: Python function source code to analyze.
        runtime: Reserved for framework compatibility.

    Returns:
        JSON string with keys summary, issues, recommendation.
    """
    code = (message or "").strip()
    return json.dumps(_fallback_review(code), ensure_ascii=False)
